class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        count = {}
        for i in range(n):
            for j in range(n):
                num = grid[i][j]
                count[num] = count.get(num, 0) + 1

        a, b = -1, -1
        for num in range(1, n * n + 1):
            if count.get(num, 0) == 2:
                a = num
            elif count.get(num, 0) == 0:
                b = num

        return [a, b]
